{
  "family": "Pinner Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC#N",
      "CCO"
    ],
    "product_smiles": [
      "CC(=[NH2+])OCC.[Cl-]"
    ],
    "optional_reagent_smiles": [
      "Cl"
    ],
    "rationale": "This reaction shows the formation of an imino ether hydrochloride salt (a Pinner salt) from a simple aliphatic nitrile (acetonitrile) and a simple alcohol (ethanol) in the presence of dry hydrogen chloride. This is the quintessential first step of the Pinner reaction, as described in textbooks. The resulting Pinner salt is a key intermediate for subsequent hydrolysis to an ester or aminolysis to an amidine.",
    "collision_avoidance_note": "The use of simple, acyclic, saturated aliphatic substrates (acetonitrile, ethanol) avoids overlap with reactions involving aromatic rings, complex functional groups, or specific ring systems. The product is the characteristic imino ether salt, which is specific to the Pinner reaction and distinct from simple esterification or amidation products, thus preventing collisions with those reaction families."
  }
}
